#include <stdio.h>

void badFileHandling() {
    FILE* file = fopen("data.txt", "r");
    if (file) {
        fclose(file);
        // Noncompliant - accessing closed file
        fprintf(file, "Hello"); 
        fclose(file); // Noncompliant - double close
    }
}

void anotherBadExample() {
    FILE* file = fopen("data.txt", "r");
    fclose(file);
    if (ftell(file) != -1) { // Noncompliant - using closed file
        // Do something
    }
}

compliant:
#include <stdio.h>

void goodFileHandling() {
    FILE* file = fopen("data.txt", "r");
    if (file) {
        fprintf(file, "Hello"); // Use before closing
        fclose(file);
        file = nullptr; // Prevent accidental reuse
    }
}

// Better: Use RAII
#include <fstream>
void modernFileHandling() {
    std::ofstream file("data.txt");
    if (file.is_open()) {
        file << "Hello"; // Automatically closed when out of scope
    }
}
